import "./SkillsPage.css";
import html5Img from '../Assets/logos/html5.svg';
import cssImg from '../Assets/logos/css.svg';
import javascriptImg from '../Assets/logos/javascript.png';
import reactjs from '../Assets/logos/reactjs.svg';
import python from '../Assets/logos/python.png';
import java from '../Assets/logos/java.png';
import solidworks from '../Assets/logos/solidworks.png';
import photoshop from '../Assets/logos/photoshop.png';
import illustrator from '../Assets/logos/illustrator.png';
import xd from '../Assets/logos/xd.png';
import figma from '../Assets/logos/figma.png';

export function SkillBox(props){
    return (
        <div className="FlexBox">
            <div className="Circle">
                <div className="Img">
                    <img src={props.src} alt="logo" />
                </div>
                <div className="SkillName">
                    <span>{props.name}</span>
                </div>
            </div>
        </div>
    );
}

export default function SkillsPage(props){
    return (
        <div className="SkillContent">
            <div className="SkillBoxContainer">
                <SkillBox name="HTML 5" src={html5Img} />
                <SkillBox name="CSS 3" src={cssImg} />
                <SkillBox name="Javascript" src={javascriptImg} />
                <SkillBox name="ReactJS" src={reactjs} />
            </div>
            <div className="SkillBoxContainer">
                <SkillBox name="Python" src={python} />
                <SkillBox name="Java" src={java} />
                <SkillBox name="SolidWorks" src={solidworks} />
            </div>
            <div className="SkillBoxContainer">
                <SkillBox name="Photoshop" src={photoshop} />
                <SkillBox name="Illlustrator" src={illustrator} />
                <SkillBox name="Adobe XD" src={xd} />
                <SkillBox name="LightRoom" src={figma} />
            </div>
        </div>
    );
}